package org.apache.commons.csv;
import static org.apache.commons.csv.Constants.BACKSLASH;
import static org.apache.commons.csv.Constants.COMMA;
import static org.apache.commons.csv.Constants.CR;
import static org.apache.commons.csv.Constants.CRLF;
import static org.apache.commons.csv.Constants.DOUBLE_QUOTE_CHAR;
import static org.apache.commons.csv.Constants.LF;
import static org.apache.commons.csv.Constants.TAB;
import java.io.IOException;
import java.io.Reader;
import java.io.Serializable;
import java.io.StringWriter;
import java.util.Arrays;
import java.util.HashSet;
import java.util.Set;

import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.assertThrows;
import static org.mockito.Mockito.mock;

public class CSVFormatTest {

    @Test
    public void testValidate() throws Exception {
        CSVFormat csvFormat = new CSVFormat(',', '"', QuoteMode.ALL, '#', '\\', true, false, "\r\n", null, new String[]{"Header"}, false, true);

        assertThrows(IllegalArgumentException.class, () -> {
            CSVFormat.class.getDeclaredMethod("validate").setAccessible(true).invoke(csvFormat);
        });

        csvFormat = new CSVFormat(',', '"', QuoteMode.ALL, null, '\\', true, false, "\r\n", null, new String[]{"Header"}, false, true);
        assertThrows(IllegalArgumentException.class, () -> {
            CSVFormat.class.getDeclaredMethod("validate").setAccessible(true).invoke(csvFormat);
        });

        csvFormat = new CSVFormat(',', '"', QuoteMode.ALL, '"', '\\', true, false, "\r\n", null, new String[]{"Header"}, false, true);
        assertThrows(IllegalArgumentException.class, () -> {
            CSVFormat.class.getDeclaredMethod("validate").setAccessible(true).invoke(csvFormat);
        });

        csvFormat = new CSVFormat(',', '"', QuoteMode.ALL, '#', '#', true, false, "\r\n", null, new String[]{"Header"}, false, true);
        assertThrows(IllegalArgumentException.class, () -> {
            CSVFormat.class.getDeclaredMethod("validate").setAccessible(true).invoke(csvFormat);
        });

        csvFormat = new CSVFormat(',', '"', QuoteMode.ALL, '#', '#', true, false, "\r\n", null, new String[]{"Header"}, false, false);
        assertThrows(IllegalArgumentException.class, () -> {
            CSVFormat.class.getDeclaredMethod("validate").setAccessible(true).invoke(csvFormat);
        });

        csvFormat = new CSVFormat(',', '"', QuoteMode.NONE, null, '\\', true, false, "\r\n", null, new String[]{"Header"}, false, true);
        assertThrows(IllegalArgumentException.class, () -> {
            CSVFormat.class.getDeclaredMethod("validate").setAccessible(true).invoke(csvFormat);
        });
    }
}

